public static int search(int[] nums, int left, int right, int target) {
    if (left >= right) {
        return -1;
    }

    int mid = (left + right) / 2;
    if (nums[mid] == target) {
        return mid;
    }
    if (nums[mid] < target) {
        return search(nums, mid + 1, right, target);
    }
    return search(nums, left, mid - 1, target);
}

