public boolean isValid(TreeNode node) {
    if (node == null) {
        return true;
    }
    if (node.left != null && node.left.val >= node.val) {
        return false;
    }
    if (node.right != null && node.right.val <= node.val) {
        return false;
    }
    return isValid(node.left) && isValid(node.right);
}

