public int fib(int n, Map<Integer, Integer> memo) {
    if (n <= 1) {
        return n;
    }
    if (memo.containsKey(n)) {
        return memo.get(n);
    }
    return fib(n - 1, memo) + fib(n - 2, memo);
}

